INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e94eb492-1452-4ee1-ae15-a653fa25b376',
  '00000000-0000-0000-0000-000000000001',
  $escape$iam Service Accounts & Roles — Machine Identities with Workload Identity Federation$escape$,
  $escape$iam service accounts are used to identify machine identities, while roles define the permissions for these identities. To manage machine identities securely, iam provides workload identity federation, which eliminates the need for long-lived keys. With workload identity federation, you can configure a workload identity pool to manage service accounts and roles. This approach ensures that service accounts are authenticated and authorized without using long-lived credentials. The iam API provides methods to create and manage service accounts, roles, and workload identity pools, making it easier to implement machine identity management.$escape$,
  $escape$gcloud iam service-accounts create my-service-account --description 'My Service Account'
gcloud iam roles create my-role --description 'My Role'
gcloud iam workload-identity-pools create my-pool --description 'My Pool'
gcloud iam service-accounts add-iam-policy-binding my-service-account --member 'serviceAccount:my-service-account@my-project.iam.gserviceaccount.com' --role 'projects/my-project/roles/my-role'$escape$,
  $escape$bash$escape$,
